        OBJC_MSGSEND_VOID(_avAudioPlayer, "prepareToPlay");
        OBJC_MSGSEND_VOID(_avAudioPlayer, "play");
        NSLog(@"BG:start play.");
        // register for audio interruption notification
        [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(onRecieveBGAudioInterruptionNotification:) name:AVAudioSessionInterruptionNotification object:nil];
    }
}

- (void)stopBGAudio {
    if (_avAudioPlayer) {
        OBJC_MSGSEND_VOID(_avAudioPlayer, "stop");
        NSLog(@"BG:stop play.");
        _avAudioPlayer = nil;
        [[NSNotificationCenter defaultCenter] removeObserver:self name:AVAudioSessionInterruptionNotification  object:nil];
    }
}

- (void)onRecieveBGAudioInterruptionNotification:(NSNotification *)notification {
    NSDictionary *userInfo = notification.userInfo;
    NSNumber *interruptionType = userInfo[AVAudioSessionInterruptionTypeKey];
    if ([interruptionType isEqualToNumber:[NSNumber numberWithInt:AVAudioSessionInterruptionTypeBegan]]) {
